// Copies tesseract.js runtime assets from node_modules into public/tesseract/
// so OCR is fully self-hosted (privacy + offline). public/tesseract is
// gitignored and regenerated by the predev/prebuild hooks.
import { cpSync, mkdirSync, readdirSync } from 'node:fs'
import { dirname, join, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const root = resolve(dirname(fileURLToPath(import.meta.url)), '..')
const out = join(root, 'public', 'tesseract')

mkdirSync(join(out, 'core'), { recursive: true })
mkdirSync(join(out, 'lang'), { recursive: true })

cpSync(
  join(root, 'node_modules/tesseract.js/dist/worker.min.js'),
  join(out, 'worker.min.js')
)

// Only the LSTM variants — the default OCR engine mode. The runtime picks
// plain/simd/relaxedsimd based on browser support.
const coreDir = join(root, 'node_modules/tesseract.js-core')
for (const name of readdirSync(coreDir)) {
  if (name.startsWith('tesseract-core') && name.includes('lstm')) {
    cpSync(join(coreDir, name), join(out, 'core', name))
  }
}

cpSync(join(root, 'node_modules/@tesseract.js-data/eng/4.0.0_best_int'), join(out, 'lang'), {
  recursive: true,
})

console.log('OCR assets copied to public/tesseract/')
